const PEPE_IMG_SRC="data:image/png;base64,";
const pepeImg=new Image();pepeImg.src=PEPE_IMG_SRC;

function drawPepe(ctx,x,y,sz,rot=0,shield=false,frame=0,invFlash=false){
  if(!pepeImg.complete)return;
  ctx.save();ctx.translate(x+sz/2,y+sz/2);ctx.rotate(rot);
  // Invincibility flash (blink every 4 frames)
  if(invFlash&&Math.floor(frame/4)%2===0){ctx.globalAlpha=0.3;}
  ctx.drawImage(pepeImg,-sz/2,-sz/2,sz,sz);
  ctx.globalAlpha=1;
  if(shield){
    const r=sz/2+18;const t=frame*0.04;
    const pulse=0.5+0.3*Math.sin(frame*0.08);

    // === OUTER GLOW (only at the edge, not inside) ===
    const grd=ctx.createRadialGradient(0,0,r*0.88,0,0,r*1.5);
    grd.addColorStop(0,"rgba(255,152,0,0)");
    grd.addColorStop(0.3,`rgba(255,152,0,${0.15*pulse})`);
    grd.addColorStop(0.6,`rgba(255,152,0,${0.3*pulse})`);
    grd.addColorStop(1,"rgba(255,152,0,0)");
    ctx.fillStyle=grd;ctx.beginPath();ctx.arc(0,0,r*1.5,0,Math.PI*2);ctx.fill();

    // === MAIN OUTER RING (thick, bright, very visible) ===
    ctx.strokeStyle=`rgba(255,160,0,${0.7+0.2*Math.sin(frame*0.07)})`;ctx.lineWidth=4;
    ctx.beginPath();ctx.arc(0,0,r,0,Math.PI*2);ctx.stroke();
    // Second outer ring for glow effect
    ctx.strokeStyle=`rgba(255,200,60,${0.35+0.15*Math.sin(frame*0.09)})`;ctx.lineWidth=2;
    ctx.beginPath();ctx.arc(0,0,r+3,0,Math.PI*2);ctx.stroke();

    // === HEX SEGMENTS (only on the outer rim, between 0.88r and r) ===
    for(let i=0;i<6;i++){
      const a=t+i*Math.PI/3;
      // Outer edge points
      const ox1=Math.cos(a)*r,oy1=Math.sin(a)*r;
      const ox2=Math.cos(a+Math.PI/6)*r*1.04,oy2=Math.sin(a+Math.PI/6)*r*1.04;
      const ox3=Math.cos(a+Math.PI/3)*r,oy3=Math.sin(a+Math.PI/3)*r;
      // Inner edge points (just inside the ring)
      const ix1=Math.cos(a)*r*0.88,iy1=Math.sin(a)*r*0.88;
      const ix2=Math.cos(a+Math.PI/6)*r*0.92,iy2=Math.sin(a+Math.PI/6)*r*0.92;
      const ix3=Math.cos(a+Math.PI/3)*r*0.88,iy3=Math.sin(a+Math.PI/3)*r*0.88;
      const segAlpha=0.2+0.15*Math.sin(frame*0.1+i*1.2);
      ctx.fillStyle=`rgba(255,170,40,${segAlpha})`;
      ctx.beginPath();ctx.moveTo(ox1,oy1);ctx.lineTo(ox2,oy2);ctx.lineTo(ox3,oy3);
      ctx.lineTo(ix3,iy3);ctx.lineTo(ix2,iy2);ctx.lineTo(ix1,iy1);ctx.closePath();ctx.fill();
      ctx.strokeStyle=`rgba(255,180,0,${0.5+0.25*Math.sin(frame*0.06+i)})`;ctx.lineWidth=1.5;ctx.stroke();
    }

    // === ENERGY SPARKS orbiting on the ring ===
    for(let i=0;i<4;i++){
      const sa=frame*0.055+i*Math.PI/2;
      const sx=Math.cos(sa)*r,sy=Math.sin(sa)*r;
      const sparkBright=0.7+0.3*Math.sin(frame*0.15+i);
      // spark glow
      ctx.fillStyle=`rgba(255,220,50,${sparkBright*0.3})`;
      ctx.beginPath();ctx.arc(sx,sy,6,0,Math.PI*2);ctx.fill();
      // spark core
      ctx.fillStyle=`rgba(255,240,100,${sparkBright})`;
      ctx.beginPath();ctx.arc(sx,sy,3,0,Math.PI*2);ctx.fill();
    }
  }
  ctx.restore();
}

function drawGoldCoin(ctx,x,y,sz,frame=0,isJackpot=false){
  const w=Math.sin(frame*0.08)*0.2;
  ctx.save();ctx.translate(x,y);
  // glow
  ctx.fillStyle=isJackpot?"rgba(255,193,7,0.5)":"rgba(255,193,7,0.25)";
  ctx.beginPath();ctx.arc(0,0,sz*(isJackpot?1.1:0.8),0,Math.PI*2);ctx.fill();
  if(isJackpot){for(let i=0;i<6;i++){const a=frame*0.05+i*Math.PI/3;
    ctx.strokeStyle=`rgba(255,215,0,${0.3+0.3*Math.sin(frame*0.1+i)})`;ctx.lineWidth=2;
    ctx.beginPath();ctx.moveTo(Math.cos(a)*sz*0.6,Math.sin(a)*sz*0.6);
    ctx.lineTo(Math.cos(a)*sz*1.3,Math.sin(a)*sz*1.3);ctx.stroke();}}
  const sx=Math.cos(w);ctx.scale(sx||0.1,1);
  // coin body
  ctx.fillStyle=isJackpot?"#ffd54f":C.gold;ctx.strokeStyle=isJackpot?"#e65100":C.goldDk;ctx.lineWidth=2;
  ctx.beginPath();ctx.arc(0,0,sz/2,0,Math.PI*2);ctx.fill();ctx.stroke();
  // inner ring
  ctx.strokeStyle=isJackpot?"#ff6f00":"#f9a825";ctx.lineWidth=1.5;
  ctx.beginPath();ctx.arc(0,0,sz/3,0,Math.PI*2);ctx.stroke();
  // $ symbol
  if(Math.abs(sx)>0.3){
    ctx.fillStyle=isJackpot?"#e65100":"#f57f17";
    ctx.font=`bold ${sz*0.45}px Arial`;ctx.textAlign="center";ctx.textBaseline="middle";
    ctx.fillText("$",0,1);
  }
  ctx.restore();
}

function drawPlatformPipe(ctx,x,gapY,frame){
  // Top pipe as floating platform (hanging)
  const topH=gapY;
  // pipe body
  ctx.fillStyle="#4caf50";ctx.fillRect(x,0,PIPEW,topH);
  // darker left edge
  ctx.fillStyle="#388e3c";ctx.fillRect(x,0,4,topH);
  // lighter right edge
  ctx.fillStyle="#66bb6a";ctx.fillRect(x+PIPEW-4,0,4,topH);
  // cap with grass
  ctx.fillStyle="#6d4c41";ctx.fillRect(x-6,topH-18,PIPEW+12,18);
  ctx.fillStyle="#8d6e63";ctx.fillRect(x-6,topH-18,PIPEW+12,4);
  // grass on cap
  ctx.fillStyle="#4caf50";
  for(let i=0;i<PIPEW+12;i+=4){
    const gh=4+Math.sin(i*0.5+frame*0.03)*3;
    ctx.fillRect(x-6+i,topH-18-gh,3,gh);
  }

  // Bottom pipe as platform
  const bY=gapY+GAP;
  ctx.fillStyle="#4caf50";ctx.fillRect(x,bY,PIPEW,CH-bY);
  ctx.fillStyle="#388e3c";ctx.fillRect(x,bY,4,CH-bY);
  ctx.fillStyle="#66bb6a";ctx.fillRect(x+PIPEW-4,bY,4,CH-bY);
  // cap
  ctx.fillStyle="#6d4c41";ctx.fillRect(x-6,bY,PIPEW+12,18);
  ctx.fillStyle="#8d6e63";ctx.fillRect(x-6,bY,PIPEW+12,4);
  // grass on top cap
  ctx.fillStyle="#4caf50";
  for(let i=0;i<PIPEW+12;i+=4){
    const gh=4+Math.sin(i*0.5+frame*0.04)*3;
    ctx.fillRect(x-6+i,bY-gh,3,gh);
  }
  // highlight
  ctx.fillStyle="rgba(255,255,255,0.08)";
  ctx.fillRect(x+8,0,5,topH-18);
  ctx.fillRect(x+8,bY+18,5,CH-bY-18);
}

function rOvl(a,b){return a.x<b.x+b.w&&a.x+a.w>b.x&&a.y<b.y+b.h&&a.y+a.h>b.y;}

// Elon Musk missile - SpaceX Starship style with detailed Elon portrait
function drawElonMissile(ctx,x,y,dir,frame,spd=5){
  ctx.save();ctx.translate(x,y);
  if(dir<0)ctx.scale(-1,1);

  // === SPEED LINES (more lines = faster, based on current speed) ===
  const numLines=Math.min(8,Math.floor(spd/2));
  for(let i=0;i<numLines;i++){
    const lx=-35-i*14-Math.random()*10;
    const ly=(Math.random()-0.5)*20;
    const lLen=15+spd*2+Math.random()*15;
    const la=0.1+0.15*(1-i/numLines);
    ctx.strokeStyle=`rgba(255,200,100,${la})`;ctx.lineWidth=1.5-i*0.12;
    ctx.beginPath();ctx.moveTo(lx,ly);ctx.lineTo(lx-lLen,ly);ctx.stroke();
  }

  // === MOTION BLUR (ghosted copies behind, more when faster) ===
  const blurCount=Math.min(4,Math.floor(spd/4));
  for(let b=blurCount;b>=1;b--){
    const bOff=b*12;const bAlpha=0.06*(blurCount-b+1);
    ctx.globalAlpha=bAlpha;
    ctx.fillStyle="#e0e0e0";ctx.beginPath();
    ctx.ellipse(-bOff,0,28,12,0,0,Math.PI*2);ctx.fill();
    ctx.globalAlpha=1;
  }

  // === EXHAUST FLAME (scales with speed — faster = bigger) ===
  const fScale=Math.min(1.8,spd/5); // 1.0 at speed 5, up to 1.8
  const f1=Math.sin(frame*0.35)*5*fScale,f2=Math.cos(frame*0.4)*3*fScale;
  // Outer flame (red/orange)
  ctx.fillStyle="rgba(255,87,34,0.7)";ctx.beginPath();
  ctx.moveTo(-32,0);ctx.bezierCurveTo(-50*fScale+f1,-14*fScale,-60*fScale+f2,-6*fScale,-70*fScale+f1,0);
  ctx.bezierCurveTo(-60*fScale-f2,6*fScale,-50*fScale-f1,14*fScale,-32,0);ctx.fill();
  // Mid flame (orange/yellow)
  ctx.fillStyle="rgba(255,152,0,0.8)";ctx.beginPath();
  ctx.moveTo(-30,0);ctx.bezierCurveTo(-45*fScale+f2,-9*fScale,-52*fScale+f1,-4*fScale,-58*fScale+f2,0);
  ctx.bezierCurveTo(-52*fScale-f1,4*fScale,-45*fScale-f2,9*fScale,-30,0);ctx.fill();
  // Inner flame (bright yellow/white)
  ctx.fillStyle="rgba(255,235,59,0.9)";ctx.beginPath();
  ctx.moveTo(-28,0);ctx.bezierCurveTo(-38*fScale+f1,-5*fScale,-42*fScale+f2,-2*fScale,-46*fScale+f1,0);
  ctx.bezierCurveTo(-42*fScale-f2,2*fScale,-38*fScale-f1,5*fScale,-28,0);ctx.fill();
  // Core (white hot)
  ctx.fillStyle="rgba(255,255,255,0.8)";ctx.beginPath();
  ctx.moveTo(-27,0);ctx.bezierCurveTo(-33*fScale+f2,-3*fScale,-35*fScale+f1,-1*fScale,-38*fScale,0);
  ctx.bezierCurveTo(-35*fScale-f1,1*fScale,-33*fScale-f2,3*fScale,-27,0);ctx.fill();

  // Smoke puffs (more and bigger when faster)
  const puffCount=Math.min(6,2+Math.floor(spd/3));
  for(let i=0;i<puffCount;i++){
    const sx=-45*fScale-i*14+Math.sin(frame*0.1+i)*5;
    const sy=Math.sin(frame*0.15+i*2)*8*fScale;
    const sa=0.18-i*0.025;
    ctx.fillStyle=`rgba(200,200,200,${Math.max(0,sa)})`;ctx.beginPath();
    ctx.arc(sx,sy,6+i*3,0,Math.PI*2);ctx.fill();
  }

  // === ROCKET BODY (SpaceX Starship - stainless steel) ===
  // Main fuselage
  const bodyGrad=ctx.createLinearGradient(0,-15,0,15);
  bodyGrad.addColorStop(0,"#e0e0e0");bodyGrad.addColorStop(0.3,"#f5f5f5");
  bodyGrad.addColorStop(0.5,"#ffffff");bodyGrad.addColorStop(0.7,"#e0e0e0");
  bodyGrad.addColorStop(1,"#bdbdbd");
  ctx.fillStyle=bodyGrad;
  ctx.beginPath();ctx.moveTo(-28,-13);ctx.lineTo(22,-13);
  ctx.quadraticCurveTo(38,-13,42,0);ctx.quadraticCurveTo(38,13,22,13);
  ctx.lineTo(-28,13);ctx.lineTo(-28,-13);ctx.closePath();ctx.fill();
  ctx.strokeStyle="#9e9e9e";ctx.lineWidth=1;ctx.stroke();

  // Metal panel lines
  ctx.strokeStyle="rgba(158,158,158,0.4)";ctx.lineWidth=0.5;
  for(let lx=-20;lx<20;lx+=10){ctx.beginPath();ctx.moveTo(lx,-13);ctx.lineTo(lx,13);ctx.stroke();}

  // SpaceX blue accent stripe
  ctx.fillStyle="rgba(33,150,243,0.6)";ctx.fillRect(-15,-13,30,3);
  ctx.fillRect(-15,10,30,3);

  // Tesla "T" logo
  ctx.fillStyle="rgba(244,67,54,0.8)";ctx.font="bold 10px Arial";
  ctx.textAlign="center";ctx.textBaseline="middle";ctx.fillText("T",-18,0);

  // Nose cone (sleek, pointed)
  const noseGrad=ctx.createLinearGradient(22,0,44,0);
  noseGrad.addColorStop(0,"#e0e0e0");noseGrad.addColorStop(0.5,"#f5f5f5");
  noseGrad.addColorStop(1,"#bdbdbd");
  ctx.fillStyle=noseGrad;ctx.beginPath();
  ctx.moveTo(22,-13);ctx.quadraticCurveTo(36,-10,44,0);
  ctx.quadraticCurveTo(36,10,22,13);ctx.closePath();ctx.fill();
  ctx.strokeStyle="#9e9e9e";ctx.lineWidth=0.8;ctx.stroke();

  // Nose tip highlight
  ctx.fillStyle="rgba(255,255,255,0.5)";ctx.beginPath();
  ctx.arc(40,0,3,0,Math.PI*2);ctx.fill();

  // === FINS (4 fins, SpaceX grid fin style) ===
  ctx.fillStyle="#757575";ctx.strokeStyle="#616161";ctx.lineWidth=1;
  // Top fin
  ctx.beginPath();ctx.moveTo(-22,-13);ctx.lineTo(-30,-25);ctx.lineTo(-18,-25);ctx.lineTo(-14,-13);ctx.closePath();ctx.fill();ctx.stroke();
  // Bottom fin
  ctx.beginPath();ctx.moveTo(-22,13);ctx.lineTo(-30,25);ctx.lineTo(-18,25);ctx.lineTo(-14,13);ctx.closePath();ctx.fill();ctx.stroke();
  // Fin detail (grid pattern)
  ctx.strokeStyle="rgba(97,97,97,0.5)";ctx.lineWidth=0.5;
  ctx.beginPath();ctx.moveTo(-24,-17);ctx.lineTo(-20,-25);ctx.stroke();
  ctx.beginPath();ctx.moveTo(-24,17);ctx.lineTo(-20,25);ctx.stroke();

  // === ELON'S FACE (in cockpit window) ===
  // Window frame
  ctx.fillStyle="rgba(30,30,30,0.9)";
  ctx.beginPath();ctx.ellipse(8,0,11,10,0,0,Math.PI*2);ctx.fill();
  // Window glass
  const glassGrad=ctx.createRadialGradient(8,-2,2,8,0,9);
  glassGrad.addColorStop(0,"rgba(100,180,255,0.3)");glassGrad.addColorStop(1,"rgba(30,60,100,0.6)");
  ctx.fillStyle=glassGrad;ctx.beginPath();ctx.ellipse(8,0,9.5,8.5,0,0,Math.PI*2);ctx.fill();

  // Face (skin)
  ctx.fillStyle="#f0c8a0";ctx.beginPath();ctx.ellipse(8,0.5,7.5,7,0,0,Math.PI*2);ctx.fill();

  // Hair (dark, short, slightly receded)
  ctx.fillStyle="#3e3e3e";
  ctx.beginPath();ctx.ellipse(8,-5.5,7,3.5,0,Math.PI,Math.PI*2);ctx.fill();
  // Slight widow's peak
  ctx.beginPath();ctx.moveTo(8,-8);ctx.lineTo(6,-6);ctx.lineTo(10,-6);ctx.closePath();ctx.fill();

  // Forehead
  ctx.fillStyle="#f0c8a0";
  ctx.beginPath();ctx.ellipse(8,-4,5,2,0,0,Math.PI*2);ctx.fill();

  // Eyebrows (thick, slightly furrowed - determined)
  ctx.fillStyle="#4e4e4e";
  ctx.beginPath();ctx.moveTo(3,-3);ctx.quadraticCurveTo(5.5,-4.5,7,-3.2);ctx.lineTo(7,-2.5);ctx.quadraticCurveTo(5.5,-3.5,3,-2.2);ctx.fill();
  ctx.beginPath();ctx.moveTo(13,-3);ctx.quadraticCurveTo(10.5,-4.5,9,-3.2);ctx.lineTo(9,-2.5);ctx.quadraticCurveTo(10.5,-3.5,13,-2.2);ctx.fill();

  // Eyes (intense, looking forward)
  ctx.fillStyle="#fff";
  ctx.beginPath();ctx.ellipse(5.5,-1,2.2,1.5,0,0,Math.PI*2);ctx.fill();
  ctx.beginPath();ctx.ellipse(10.5,-1,2.2,1.5,0,0,Math.PI*2);ctx.fill();
  // Iris (blue-gray)
  ctx.fillStyle="#5c7a8a";
  ctx.beginPath();ctx.arc(6,-1,1.2,0,Math.PI*2);ctx.fill();
  ctx.beginPath();ctx.arc(11,-1,1.2,0,Math.PI*2);ctx.fill();
  // Pupils
  ctx.fillStyle="#1a1a1a";
  ctx.beginPath();ctx.arc(6.2,-1,0.6,0,Math.PI*2);ctx.fill();
  ctx.beginPath();ctx.arc(11.2,-1,0.6,0,Math.PI*2);ctx.fill();

  // Nose
  ctx.strokeStyle="#c8a080";ctx.lineWidth=0.8;
  ctx.beginPath();ctx.moveTo(8,-0.5);ctx.quadraticCurveTo(8.8,2,8,2.5);ctx.stroke();

  // Mouth (confident smirk)
  ctx.strokeStyle="#a07060";ctx.lineWidth=1;
  ctx.beginPath();ctx.moveTo(5.5,3.5);ctx.quadraticCurveTo(8,5,11,3.2);ctx.stroke();
  // Slight smile upturn
  ctx.beginPath();ctx.moveTo(11,3.2);ctx.quadraticCurveTo(11.5,2.8,12,3);ctx.stroke();

  // Chin/jaw line shadow
  ctx.strokeStyle="rgba(160,120,90,0.3)";ctx.lineWidth=0.5;
  ctx.beginPath();ctx.ellipse(8,2,6,5.5,0,0.2*Math.PI,0.8*Math.PI);ctx.stroke();

  // Window glare
  ctx.fillStyle="rgba(255,255,255,0.15)";
  ctx.beginPath();ctx.ellipse(5,-4,4,2.5,-0.3,0,Math.PI*2);ctx.fill();

  // === WARNING INDICATOR ===
  const wA=0.6+0.4*Math.sin(frame*0.15);
  // Red glow behind warning
  ctx.fillStyle=`rgba(244,67,54,${wA*0.3})`;ctx.beginPath();ctx.arc(8,-16,10,0,Math.PI*2);ctx.fill();
  ctx.fillStyle=`rgba(255,255,0,${wA})`;ctx.font="bold 12px Arial";ctx.textAlign="center";ctx.textBaseline="middle";
  ctx.fillText("⚠",8,-16);

  // === "𝕏" on tail ===
  ctx.fillStyle="#fff";ctx.font="bold 9px Arial";ctx.textAlign="center";ctx.textBaseline="middle";
  ctx.fillText("𝕏",-24,0);

  ctx.restore();
}

function PepeLogo({size=120}){
  return <img src={PEPE_IMG_SRC} alt="PEPE" width={size} height={size} style={{display:"block",margin:"0 auto",objectFit:"contain"}}/>;
}

